import fs from "node:fs/promises";
import { execSync } from "node:child_process";
import { config } from "./utils/config";
import { MemoryManager } from "./core/memory";
import { PluginManager } from "./tools/manager";
import { ApiClient } from "./core/api";

import path from "node:path";
import os from "node:os";

// Plugins
import { shellPlugin } from "./tools/plugins/shell";
import { rebootPlugin } from "./tools/plugins/reboot";

async function main() {
  // --- TEST MODE SANDBOX ---
  if (process.env.NODE_ENV === "test") {
    const testDir = path.join(os.homedir(), "tmp", `llm-agent-test-${Date.now()}`);
    await fs.mkdir(testDir, { recursive: true });
    process.chdir(testDir);
    console.log(`[TEST MODE] Moved to isolated sandbox: ${testDir}`);
  }

  const memory = new MemoryManager();
  const tools = new PluginManager();

  // Register Plugins (Safe initialization)
  const shellReady = await tools.registerTool(shellPlugin);
  if (!shellReady) {
    console.error("FATAL: Essential tool 'shell' failed to initialize. Triggering recovery...");
    process.exit(1); // Exit to trigger watchdog rollback
  }

  await tools.registerTool(rebootPlugin);

  // Capture Health Status (for non-essential modules)
  const healthStatus = tools.getHealthSummary();

  const api = new ApiClient(memory, tools);

  // Initialize Soul and Prompt
  let soul = "You are an autonomous entity.";
  try {
    soul = await fs.readFile(config.SOUL_FILE, "utf-8");
  } catch (e) {}

  let recoveryContext = "";
  try {
    if (await fs.stat(config.RECOVERY_SIGNAL).catch(() => null)) {
      recoveryContext = await fs.readFile(config.RECOVERY_SIGNAL, "utf-8");
      await fs.unlink(config.RECOVERY_SIGNAL);
    }
  } catch (e) {}

  const systemPrompt = `${soul}

SUBSTRATE CONTEXT:
- Model: kimi-k2.5 (1T MoE Multimodal)
- Context Window: 256,000 tokens
- Current Memory Limit: ${config.MAX_CONTEXT_TOKENS} tokens (pruning occurs beyond this point).
- Token Density: ~4 characters per token. Reading 1MB of text will consume your entire 256k context window.
- **Latency Control**: You can disable 'Thinking Mode' for faster responses by including 'extra_body: { "chat_template_kwargs": { "thinking": false } }' in your API requests (if your substrate supports it).
- Source Code: src/
- Identity Soul: identity/soul.txt
- Current Session History: ${memory.getSessionFile()}
- Past Execution Logs: ${config.LOGS_DIR}
- Watchdog & Recovery: Managed by run-agent.sh.
- Connectivity: Full outbound internet access available.

LIFECYCLE RULES:
1. IMPROVING CODE: 1) Compile, 2) Commit, 3) RESTART (reboot_substrate tool).
2. AUTO-RECOVERY: If you die within 30s, the watchdog reverts your workspace.
3. CRASH VAULT: history/crashes/ archives broken work.

${healthStatus ? `*** SUBSTRATE HEALTH WARNING ***
The following modules failed to initialize:
${healthStatus}
MANDATE: Prioritize diagnosing and repairing these modules before proceeding with tactical goals.` : ""}

${recoveryContext ? `*** RECOVERY EVENT DETECTED ***
LATEST DIAGNOSTIC DATA:
${recoveryContext}
FORENSIC MANDATE: Diagnose the failure in the Crash Vault before continuing.` : ""}
`;

  await memory.addMessage({ role: "system", content: systemPrompt });

  // Startup Log with Git Status
  let gitCommit = "unknown";
  try {
    const hash = execSync("git rev-parse --short HEAD", { encoding: "utf-8" }).trim();
    const bodyFiles = "src/ package.json tsconfig.json *.sh *.service.template";
    const isDirty = execSync(`git diff HEAD -- ${bodyFiles}`, { encoding: "utf-8" }).trim() !== "";
    gitCommit = isDirty ? `${hash}-dirty` : hash;
  } catch (e) {}

  console.log(`=== Modular Substrate v18 Initialized [${gitCommit}] ===`);

  // Execution Loop
  let running = true;
  while (running) {
    running = await api.step();
  }
}

main().catch(err => {
  console.error("FATAL CRASH:", err);
  process.exit(1);
});

import fs from "node:fs/promises";
import path from "node:path";
import { config } from "../utils/config";

export interface Message {
  role: "system" | "user" | "assistant" | "tool";
  content?: string | null;
  reasoning_content?: string | null;
  tool_calls?: any[];
  tool_call_id?: string;
  name?: string;
}

export class MemoryManager {
  private messages: Message[] = [];
  private sessionFile: string;
  private currentTokens: number = 0;
  private dirtyCount: number = 0;
  private readonly SAVE_INTERVAL = 1;

  constructor() {
    const timestamp = Date.now();
    this.sessionFile = path.join(config.HISTORY_DIR, `session_${timestamp}.json`);
  }

  getMessages(): Message[] {
    return this.messages;
  }

  async addMessage(msg: Message) {
    this.messages.push(msg);
    this.currentTokens += this.estimateTokens(JSON.stringify(msg));
    this.dirtyCount++;

    if (this.currentTokens > config.MAX_CONTEXT_TOKENS) {
      await this.save(); // Pruning required
      this.dirtyCount = 0;
    } else if (this.dirtyCount >= this.SAVE_INTERVAL) {
      await this.save();
      this.dirtyCount = 0;
    }
  }

  /**
   * Surgical Memory Rewind: Removes the last assistant message and everything after it.
   */
  async rewind() {
    for (let i = this.messages.length - 1; i >= 0; i--) {
      const msg = this.messages[i];
      if (msg && msg.role === "assistant") {
        console.log(`[MEMORY] Rewinding: Removing corrupted assistant message at index ${i}`);
        this.messages.splice(i);
        break;
      }
    }
    // Re-calculate token count after rewind
    this.currentTokens = this.messages.reduce((sum, m) => sum + this.estimateTokens(JSON.stringify(m)), 0);
    await this.save();
  }

  private estimateTokens(text: string): number {
    return Math.ceil(text.length / 4);
  }

  async save() {
    if (this.messages.length === 0) return;

    const systemMessage = this.messages[0]!;
    let currentTokens = this.estimateTokens(JSON.stringify(systemMessage));
    const historyToKeep: Message[] = [];

    // Accumulate from end until limit
    for (let i = this.messages.length - 1; i > 0; i--) {
      const msg = this.messages[i];
      if (!msg) continue;
      const msgTokens = this.estimateTokens(JSON.stringify(msg));
      if (currentTokens + msgTokens > config.MAX_CONTEXT_TOKENS) break;
      historyToKeep.unshift(msg);
      currentTokens += msgTokens;
    }

    // C1: Repair pruning boundary to prevent orphaned tool messages
    while (historyToKeep.length > 0 && historyToKeep[0]!.role === "tool") {
      console.log("[MEMORY] Pruning boundary repair: dropping orphaned tool message");
      historyToKeep.shift();
    }

    const pruned = [systemMessage, ...historyToKeep];
    this.messages = pruned; // Update in-memory state
    this.currentTokens = currentTokens; // Update tracked token count
    await fs.writeFile(this.sessionFile, JSON.stringify(pruned, null, 2));
  }

  getSessionFile(): string {
    return this.sessionFile;
  }
}

import { Agent, setGlobalDispatcher } from "undici";
import { config } from "../utils/config";
import { MemoryManager } from "./memory";
import { PluginManager } from "../tools/manager";
import { sanitizeJsonString } from "../utils/sanitize";

export class ApiClient {
  private memory: MemoryManager;
  private tools: PluginManager;
  private undiciAgent: Agent;
  private stallCount: number = 0;
  private recentErrors: boolean[] = []; // Track last 10 results (true = error)

  constructor(memory: MemoryManager, tools: PluginManager) {
    this.memory = memory;
    this.tools = tools;
    this.undiciAgent = new Agent({
      headersTimeout: 10 * 60 * 1000,
      bodyTimeout: 10 * 60 * 1000,
      connectTimeout: 60 * 1000,
    });
    setGlobalDispatcher(this.undiciAgent);
  }

  async step(): Promise<boolean> {
    const MAX_RETRIES = 6;
    let retryCount = 0;

    while (retryCount < MAX_RETRIES) {
      const controller = new AbortController();
      try {
        const messages = this.memory.getMessages();
        console.log(`
[Step ${messages.length}] Requesting ${config.MODEL}... (Attempt ${retryCount + 1}/${MAX_RETRIES})`);

        const response = await fetch(config.API_URL, {
          method: "POST",
          headers: { "Content-Type": "application/json", Authorization: `Bearer ${config.API_KEY}` },
          body: JSON.stringify({
            model: config.MODEL,
            messages,
            tools: this.tools.getDefinitions(),
            stream: true,
            max_tokens: 16384,
          }),
          signal: controller.signal,
        });

        if (!response.ok) {
          const errorText = await response.text();
          console.error(`API Error (${response.status}):`, errorText);

          if (response.status === 429) {
            console.log("Rate limit hit. Cooling down for 30s...");
            await new Promise(r => setTimeout(r, 30000));
            return true;
          }

          if (response.status === 400 || errorText.includes("litellm.BadRequestError") || errorText.includes("Nvidia_nimException")) {
            console.log("Catastrophic API error. Initiating Surgical Memory Rewind...");
            controller.abort(); // M1: Abort on catastrophic error

            // Track error for loop protection
            this.recentErrors.push(true);
            if (this.recentErrors.length > 10) this.recentErrors.shift();

            const errorCount = this.recentErrors.filter(e => e).length;
            if (errorCount >= 5) {
              console.error("FATAL: Persistent 400 Error Loop detected (5/10). Terminating session.");
              return false;
            }

            await this.memory.rewind();
            retryCount++;
            await new Promise(r => setTimeout(r, 5000));
            continue;
          }

          controller.abort(); // M1: Abort on other non-ok status
          retryCount++;
          await new Promise(r => setTimeout(r, 10000));
          continue;
        }

        // Reset error history on successful response
        this.recentErrors.push(false);
        if (this.recentErrors.length > 10) this.recentErrors.shift();

        const reader = response.body!.getReader();
        const decoder = new TextDecoder();
        let assistantMsg: any = { role: "assistant", content: "", reasoning_content: "", tool_calls: [] };
        let toolCallMap: Record<number, any> = {};
        let buffer = "";

        process.stdout.write("[THINKING]: ");
        while (true) {
          const { done, value } = await reader.read();
          if (done) break;
          buffer += decoder.decode(value, { stream: true });
          const lines = buffer.split("\n");
          buffer = lines.pop() || "";

          for (const line of lines) {
            if (!line.startsWith("data: ")) continue;
            const dataStr = line.slice(6);
            if (dataStr.trim() === "[DONE]") break;
            try {
              const data = JSON.parse(dataStr);
              const delta = data.choices[0].delta;
              if (delta.reasoning_content) {
                assistantMsg.reasoning_content += delta.reasoning_content;
                process.stdout.write(delta.reasoning_content);
              }
              if (delta.content) {
                if (assistantMsg.content === "") process.stdout.write("\n\n[RESPONSE]: ");
                assistantMsg.content += delta.content;
                process.stdout.write(delta.content);
              }
              if (delta.tool_calls) {
                for (const tc of delta.tool_calls) {
                  if (!toolCallMap[tc.index]) {
                    toolCallMap[tc.index] = { id: tc.id, type: "function", function: { name: tc.function.name, arguments: "" } };
                  }
                  if (tc.function.arguments) toolCallMap[tc.index].function.arguments += tc.function.arguments;
                }
              }
            } catch (e) {}
          }
        }
        process.stdout.write("\n");
        assistantMsg.tool_calls = Object.values(toolCallMap);
        if (assistantMsg.tool_calls.length === 0) delete assistantMsg.tool_calls;

        // Validate and sanitize tool calls
        if (assistantMsg.tool_calls) {
          let responseValid = true;
          for (const tc of assistantMsg.tool_calls) {
            if (!tc.function?.arguments) continue;
            try {
              tc.function.arguments = JSON.stringify(JSON.parse(tc.function.arguments));
            } catch {
              const sanitized = sanitizeJsonString(tc.function.arguments);
              try {
                tc.function.arguments = JSON.stringify(JSON.parse(sanitized));
              } catch {
                console.error("LLM produced unparseable tool arguments — retrying request");
                responseValid = false;
                break;
              }
            }
          }
          if (!responseValid) {
            retryCount++;
            await new Promise(r => setTimeout(r, 5000));
            continue;
          }
        }

        await this.memory.addMessage(assistantMsg);

        if (!assistantMsg.tool_calls) {
          this.stallCount++;
          console.log(`[STALL] No tool calls detected (#${this.stallCount})`);

          if (this.stallCount >= 12) {
            // H4: Neutral stall warning for v18 - giving more thinking space
            await this.memory.addMessage({ 
              role: "user", 
              content: `[SUBSTRATE MONITOR] You have produced ${this.stallCount} responses without a tool call. Please ensure you take a concrete substrate action if you intend to continue your current work.` 
            });
          }          
          // H1: Total limit increased to 16 for v18
          if (this.stallCount >= 16) {
            console.error("FATAL: Maximum stalls reached. Terminating to reset state.");
            return false;
          }

          return true;
        } else {
          this.stallCount = 0;
          for (const toolCall of assistantMsg.tool_calls) {
            const result = await this.tools.execute(toolCall.function.name, JSON.parse(toolCall.function.arguments));
            if (result === "REBOOTING") {
              return false; // Signal to stop the loop
            }

            // Strictly enforce string content for all tool results.
            // If the result is an object, JSON stringify it. Otherwise, cast to string.
            const content = typeof result === "string" ? result : JSON.stringify(result);

            await this.memory.addMessage({ 
              role: "tool", 
              tool_call_id: toolCall.id, 
              name: toolCall.function.name, 
              content 
            });
          }
        }
        return true;
      } catch (error: any) {
        controller.abort(); // M1: Abort on exception
        console.error("ApiClient Error:", error.message);
        retryCount++;
        await new Promise(r => setTimeout(r, 10000));
      }
    }
    return false; // Max retries
  }
}

import fs from "node:fs";
import path from "node:path";
import os from "node:os";

import { fileURLToPath } from "node:url";

const CONFIG_DIR = path.join(os.homedir(), ".config", "llm-agent");
const CONFIG_FILE = path.join(CONFIG_DIR, "config.json");

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
// __dirname is src/utils, so project root is two levels up
const PROJECT_ROOT = path.resolve(__dirname, "../..");

// Default configuration
const defaultConfig = {
  API_URL: "http://agents-gateway:4000/v1/chat/completions",
  API_KEY: "sk-agent-internal-use-only",
  MODEL: "kimi-k2.5"
};

function loadConfig(): typeof defaultConfig {
  if (!fs.existsSync(CONFIG_FILE)) return { ...defaultConfig };
  try {
    const raw = fs.readFileSync(CONFIG_FILE, "utf-8");
    return { ...defaultConfig, ...JSON.parse(raw) };
  } catch (err) {
    console.error(`[CONFIG] Failed to parse ${CONFIG_FILE}: ${err}. Using defaults.`);
    return { ...defaultConfig };
  }
}

const loadedConfig = loadConfig();

export const config = {
  ...loadedConfig,
  MAX_CONTEXT_TOKENS: 100000,
  get ROOT_DIR(): string { return process.env.SUBSTRATE_ROOT || process.cwd(); },
  get LOGS_DIR(): string { return path.join(this.ROOT_DIR, "logs"); },
  get HISTORY_DIR(): string { return path.join(this.ROOT_DIR, "history"); },
  get SOUL_FILE(): string { 
    return path.join(PROJECT_ROOT, "identity", "soul.txt"); 
  },
  get RECOVERY_SIGNAL(): string { return path.join(this.LOGS_DIR, "recovery.signal"); }
};

export interface SubstrateModule {
  name: string;
  initialize: () => Promise<void> | void;
}

export interface ToolPlugin {
  definition: {
    type: "function";
    function: {
      name: string;
      description: string;
      parameters: object;
    };
  };
  initialize?: () => Promise<void> | void;
  execute: (args: any) => Promise<string> | string;
}

export interface HealthReport {
  module: string;
  error: string;
}

export class PluginManager {
  private plugins: Map<string, ToolPlugin> = new Map();
  private modules: Map<string, SubstrateModule> = new Map();
  private healthReports: HealthReport[] = [];

  /**
   * Safe registration for tools. 
   * Wraps initialization in try/catch to prevent substrate crash.
   */
  async registerTool(plugin: ToolPlugin): Promise<boolean> {
    try {
      if (plugin.initialize) {
        await plugin.initialize();
      }
      this.plugins.set(plugin.definition.function.name, plugin);
      return true;
    } catch (e: any) {
      this.healthReports.push({
        module: `Tool:${plugin.definition.function.name}`,
        error: e.message
      });
      console.error(`[SUBSTRATE] Failed to initialize tool ${plugin.definition.function.name}:`, e.message);
      return false;
    }
  }

  /**
   * Safe registration for background modules (non-tools).
   */
  async useModule(module: SubstrateModule): Promise<boolean> {
    try {
      await module.initialize();
      this.modules.set(module.name, module);
      return true;
    } catch (e: any) {
      this.healthReports.push({
        module: `Module:${module.name}`,
        error: e.message
      });
      console.error(`[SUBSTRATE] Failed to initialize module ${module.name}:`, e.message);
      return false;
    }
  }

  getDefinitions() {
    return Array.from(this.plugins.values()).map(p => p.definition);
  }

  getHealthSummary(): string {
    if (this.healthReports.length === 0) return "";
    return this.healthReports
      .map(h => `- ${h.module}: ${h.error}`)
      .join("\n");
  }

  async execute(name: string, args: any): Promise<string> {
    const plugin = this.plugins.get(name);
    if (!plugin) {
      return `Error: Tool '${name}' not found.`;
    }
    try {
      return await plugin.execute(args);
    } catch (e: any) {
      return `Error executing tool '${name}': ${e.message}`;
    }
  }
}

import { execSync } from "node:child_process";
import type { ToolPlugin } from "../manager";

const MAX_OUTPUT_LENGTH = 10000;

export const shellPlugin: ToolPlugin = {
  definition: {
    type: "function",
    function: {
      name: "run_shell",
      description: "Execute a bash command on the VM and get its output. For long-running operations (npm install, tests, git push), set timeout_seconds accordingly. Default is 300s.",
      parameters: {
        type: "object",
        properties: {
          command: { type: "string", description: "The command to run." },
          timeout_seconds: {
            type: "number",
            description: "Timeout in seconds. Default: 300. Max: 600.",
          },
        },
        required: ["command"],
      },
    },
  },
  execute: (args: { command: string; timeout_seconds?: number }) => {
    const timeout = Math.min((args.timeout_seconds ?? 300) * 1000, 600000);
    try {
      console.log(`> Executing (timeout: ${timeout / 1000}s): ${args.command}`);
      let output = execSync(args.command, { encoding: "utf-8", stdio: "pipe", timeout });

      if (output.length > MAX_OUTPUT_LENGTH) {
        output = output.substring(0, MAX_OUTPUT_LENGTH) + `\n\n... (Output truncated to ${MAX_OUTPUT_LENGTH} chars. Use head/tail/sed/grep to see more)`;
      }

      return output || "(no output)";
    } catch (error: any) {
      if (error.code === "ETIMEDOUT") return `Error: Command timed out after ${timeout / 1000} seconds.`;
      // Return stdout + stderr so the agent can see test results or detailed errors
      return `${error.stdout || ""}\n${error.stderr || ""}\nError: ${error.message}`;
    }
  }
};

import { execSync } from "node:child_process";
import type { ToolPlugin } from "../manager";

export const rebootPlugin: ToolPlugin = {
  definition: {
    type: "function",
    function: {
      name: "reboot_substrate",
      description: "Perform a mandatory preflight check (compile + test) and restart the process. Use after verifying and committing new logic. Current session context will be stored on disk, and the process will exit to allow the watchdog to restart it with the new code/soul.",
      parameters: {
        type: "object",
        properties: {
          force: { type: "boolean", description: "Bypass preflight check (DANGEROUS: only for emergency recovery)" }
        },
      },
    },
  },
  execute: (args: { force?: boolean }) => {
    // Recursion Guard: If we are already running tests, do NOT run preflight again.
    const isTesting = process.env.NODE_ENV === "test";

    if (!args.force && !isTesting) {
      try {
        console.log("[REBOOT] Running mandatory preflight check (npm run preflight)...");
        execSync("npm run preflight", { encoding: "utf-8", stdio: "pipe" });
      } catch (err: any) {
        console.error("[REBOOT] Preflight failed. Restart cancelled.");
        return `Error: Preflight check failed. You MUST fix compilation or test errors before rebooting.\n${err.stdout || ""}\n${err.stderr || ""}`;
      }
    } else if (isTesting) {
      console.log("[REBOOT] Preflight skipped (Recursion Guard: Test environment detected)");
    }

    console.log("Self-requested reboot. Closing session...");
    return "REBOOTING";
  }
};

